ChampionShipConfig = {}

function ChampionShipConfig:init()
    local config = FileUtil.getConfigFromYml("setting/ChampionShipConfig.yml")
    if not config then
        return
    end

    ChampionShipConfig.gameStartPos = {}
    for i, pos in ipairs(config.gameStartPos) do
        ChampionShipConfig.gameStartPos[i] = VectorUtil.newVector4(pos.x, pos.y, pos.z, pos.w)
    end

    --铁笼方块区域
    ChampionShipConfig.cageBlockRegion = {}
    for i, pos in ipairs(config.cageBlockRegion) do
        ChampionShipConfig.cageBlockRegion[i] = {
            StringUtil.split(pos.x, ",", false, true),
            StringUtil.split(pos.y, ",", false, true),
            StringUtil.split(pos.z, ",", false, true),
        }
    end

    ChampionShipConfig.cageBlockId = tonumber(config.cageBlockId) or 0 --铁笼方块ID
    ChampionShipConfig.openCageBlockSound = tonumber(config.openCageBlockSound) or 0 --打开铁笼音效
    ChampionShipConfig.waitGameMusic = tonumber(config.waitGameMusic) or 0 --等待游戏开始的背景音乐
    ChampionShipConfig.waitGameStartMusic1 = tonumber(config.waitGameStartMusic1) or 0 --等待游戏开始的背景音乐1
    ChampionShipConfig.waitGameStartMusic2 = tonumber(config.waitGameStartMusic2) or 0 --等待游戏开始的背景音乐2
    ChampionShipConfig.playMusic2Time = tonumber(config.playMusic2Time) or 3 --播放背景音乐2时间(s)
    ChampionShipConfig.waitPlayerNum = tonumber(config.waitPlayerNum) or 8 --等待玩家人数
    ChampionShipConfig.waitPlayerCountDownTime = tonumber(config.waitPlayerCountDownTime) or 3 --等待玩家加入倒计时(s)
    ChampionShipConfig.waitGameStartCountDownTime = tonumber(config.waitGameStartCountDownTime) or 3 --等待游戏开始倒计时(s)
    ChampionShipConfig.gameTime = tonumber(config.gameTime) or 60 --比赛时间
    ChampionShipConfig.gameStartMusic = tonumber(config.gameStartMusic) or 0 --游戏开始的背景音乐

    --倒计时飘字配置
    ChampionShipConfig.floatNumberPos = VectorUtil.newVector3(config.floatNumberConfig[1].x,
            config.floatNumberConfig[1].y, config.floatNumberConfig[1].z)
    ChampionShipConfig.floatNumberScale = tonumber(config.floatNumberConfig[1].scale) or 1
    ChampionShipConfig.floatNumberColor = tonumber(config.floatNumberConfig[1].color) or 1
    ChampionShipConfig.floatNumberSpeed = tonumber(config.floatNumberConfig[1].speed) or 1.0
    ChampionShipConfig.floatNumberTime = tonumber(config.floatNumberConfig[1].time) or 900

    --ChampionShipConfig:createCageBlockRegion()

    --LogUtil.log("ChampionShipConfig " .. inspect.inspect(ChampionShipConfig))
end

function ChampionShipConfig:randomGameStartPos()
    local count = #ChampionShipConfig.gameStartPos
    for i = 1, count do
       local index = math.random(count)
        ChampionShipConfig.gameStartPos[i], ChampionShipConfig.gameStartPos[index] =
        ChampionShipConfig.gameStartPos[index], ChampionShipConfig.gameStartPos[i]
    end
end

function ChampionShipConfig:getGameStartPos(index)
    if index < 1 then
        return nil
    end

    local count = #ChampionShipConfig.gameStartPos
    if index > count then
        return ChampionShipConfig.gameStartPos[index % count]
    end

    return ChampionShipConfig.gameStartPos[index]
end

